elf._t</span> = <span class=\"kw\">None</span>\n    <span class=\"dc\">self._c</span>: <span class=\"kw\">list</span> = []\n    <span class=\"dc\">self._w</span> = <span class=\"kw\">None</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">from_</span>(<span class=\"dc\">self</span>, <span class=\"dc\">t</span>): <span class=\"dc\">self._t</span> = <span class=\"dc\">t</span>; <span class=\"kw\">return self</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">select</span>(<span class=\"dc\">self</span>, *<span class=\"dc\">c</span>): <span class=\"dc\">self._c</span>.<span class=\"fn\">extend</span>(<span class=\"dc\">c</span>); <span class=\"kw\">return self</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">where</span>(<span class=\"dc\">self</span>, <span class=\"dc\">w</span>):  <span class=\"dc\">self._w</span> = <span class=\"dc\">w</span>; <span class=\"kw\">return self</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">build</span>(<span class=\"dc\">self</span>) -&gt; <span class=\"kw\">str</span>:\n    <span class=\"dc\">q</span> = <span class=\"st\">f\"SELECT {{\\\", \\\".join(self._c)}} FROM {{self._t}}\"</span>\n    <span class=\"kw\">if</span> <span class=\"dc\">self._w</span>: <span class=\"dc\">q</span> += <span class=\"st\">f\" WHERE {{self._w}}\"</span>\n    <span class=\"kw\">return</span> <span class=\"dc\">q</span>", "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">QueryBuilder</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">initialize</span>\n    <span class=\"dc\">@t</span>, <span class=\"dc\">@c</span>, <span class=\"dc\">@w</span> = <span class=\"kw\">nil</span>, [], <span class=\"kw\">nil</span>\n  <span class=\"kw\">end</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">from</span>(<span class=\"dc\">t</span>)   = <span class=\"fn\">tap</span> { <span class=\"dc\">@t</span> = <span class=\"dc\">t</span> }\n  <span class=\"kw\">def</span> <span class=\"fn\">select</span>(*<span class=\"dc\">c</span>) = <span class=\"fn\">tap</span> { <span class=\"dc\">@c</span> += <span class=\"dc\">c</span> }\n  <span class=\"kw\">def</span> <span class=\"fn\">where</span>(<span class=\"dc\">w</span>)   = <span class=\"fn\">tap</span> { <span class=\"dc\">@w</span> = <span class=\"dc\">w</span> }\n\n  <span class=\"kw\">def</span> <span class=\"fn\">build</span>\n    <span class=\"dc\">q</span> = <span class=\"st\">\"SELECT #{{@c.join(\\\", \\\")} FROM #{{@t}}\"</span>\n    <span class=\"dc\">q</span> += <span class=\"st\">\" WHERE #{{@w}}\"</span> <span class=\"kw\">if</span> <span class=\"dc\">@w</span>\n    <span class=\"dc\">q</span>\n  <span class=\"kw\">end</span>\n<span class=\"kw\">end</span>"}

